import{_ as e,o as t,c as r,a3 as l}from"./chunks/framework.BTFg6ESq.js";const g=JSON.parse('{"title":"上下文分析器 (Context Analyzer)","description":"","frontmatter":{},"headers":[],"relativePath":"user-guide/tools/llm-chat/context-pipeline/analyzer.md","filePath":"user-guide/tools/llm-chat/context-pipeline/analyzer.md","lastUpdated":1778244893000}'),o={name:"user-guide/tools/llm-chat/context-pipeline/analyzer.md"};function i(n,a,s,u,c,d){return t(),r("div",null,[...a[0]||(a[0]=[l('<h1 id="上下文分析器-context-analyzer" tabindex="-1">上下文分析器 (Context Analyzer) <a class="header-anchor" href="#上下文分析器-context-analyzer" aria-label="Permalink to &quot;上下文分析器 (Context Analyzer)&quot;">​</a></h1><p>上下文分析器是一个强大的调试工具，它允许您在消息发送给 LLM 之前，查看并分析经过“上下文后处理管道”处理后的最终状态。它可以帮助您理解宏是如何展开的、世界书是如何注入的、以及 Token 是如何分布的。</p><h2 id="_1-核心功能" tabindex="-1">1. 核心功能 <a class="header-anchor" href="#_1-核心功能" aria-label="Permalink to &quot;1. 核心功能&quot;">​</a></h2><p>上下文分析器提供五个维度的深度视图：</p><h3 id="结构化视图-structured-view" tabindex="-1">结构化视图 (Structured View) <a class="header-anchor" href="#结构化视图-structured-view" aria-label="Permalink to &quot;结构化视图 (Structured View)&quot;">​</a></h3><ul><li><strong>智能体快照</strong>：显示当前使用的智能体名称、模型和配置信息。</li><li><strong>统计面板</strong>：提供 Token 和字符的详细分布，包括预设消息、会话历史、后处理消耗和世界书消耗。</li><li><strong>消息溯源</strong>：标记每条消息的来源（预设、历史、注入），并显示其 Token 消耗和字符数。</li><li><strong>附件分析</strong>：显示消息中包含的附件及其 Token 消耗，并标记是否使用了转写。</li></ul><h3 id="原始请求-raw-request" tabindex="-1">原始请求 (Raw Request) <a class="header-anchor" href="#原始请求-raw-request" aria-label="Permalink to &quot;原始请求 (Raw Request)&quot;">​</a></h3><ul><li><strong>API 模拟</strong>：以标准 JSON 格式展示最终发送给模型供应商的请求体。</li><li><strong>参数展开</strong>：显示所有模型参数（如 Temperature, Top-P 等）和自定义参数的最终值。</li><li><strong>消息序列</strong>：展示经过管道处理后的纯净消息数组。</li></ul><h3 id="内容分析-analysis-chart" tabindex="-1">内容分析 (Analysis Chart) <a class="header-anchor" href="#内容分析-analysis-chart" aria-label="Permalink to &quot;内容分析 (Analysis Chart)&quot;">​</a></h3><ul><li><strong>可视化占比</strong>：通过饼图直观展示不同部分（预设、历史、世界书、后处理）的 Token 或字符占比。</li><li><strong>详细数据表</strong>：提供精确的数值和百分比，帮助您优化长文本上下文。</li></ul><div><h3 id="宏调试-macro-debug" tabindex="-1">宏调试 (Macro Debug) <a class="header-anchor" href="#宏调试-macro-debug" aria-label="Permalink to &quot;宏调试 (Macro Debug)&quot;">​</a></h3><ul><li><strong>宏检测</strong>：自动识别文本中使用的所有宏（如 <code>{{time}}</code>, <code>{{tools}}</code> 等）。</li><li><strong>执行预览</strong>：显示宏展开后的实时结果。</li><li><strong>替换对比</strong>：提供类似 Git diff 的差异视图，对比宏展开前后的文本变化。</li></ul></div><h3 id="变量状态-variables-view" tabindex="-1">变量状态 (Variables View) <a class="header-anchor" href="#变量状态-variables-view" aria-label="Permalink to &quot;变量状态 (Variables View)&quot;">​</a></h3><ul><li><strong>快照追踪</strong>：显示会话中通过 <code>&lt;svar /&gt;</code> 标签定义的变量及其当前值。</li><li><strong>路径与类型</strong>：展示变量的完整路径（如 <code>character.hp</code>）及其数据类型。</li></ul><h2 id="_2-激活世界书分析" tabindex="-1">2. 激活世界书分析 <a class="header-anchor" href="#_2-激活世界书分析" aria-label="Permalink to &quot;2. 激活世界书分析&quot;">​</a></h2><p>当世界书条目被激活并注入上下文时，分析器会显示专门的“激活的世界书条目”区域：</p><ul><li><strong>位置标记</strong>：显示条目被注入的具体位置（如：角色设定前、作者注释后、指定深度等）。</li><li><strong>关键词匹配</strong>：展示触发该条目注入的关键词。</li><li><strong>内容预览</strong>：查看注入到上下文中的原始文本。</li></ul><h2 id="_3-使用场景" tabindex="-1">3. 使用场景 <a class="header-anchor" href="#_3-使用场景" aria-label="Permalink to &quot;3. 使用场景&quot;">​</a></h2><ul><li><strong>调试宏错误</strong>：当宏展开不符合预期时，通过“宏调试”视图查看原始输入与处理后的差异。</li><li><strong>优化 Token 消耗</strong>：通过“内容分析”发现哪个部分占用了过多上下文，从而调整截断策略或压缩配置。</li><li><strong>验证管道逻辑</strong>：确认正则替换、世界书注入和上下文压缩是否按预期工作。</li><li><strong>模拟请求排错</strong>：如果 API 报错，可以通过“原始请求”视图复制 JSON 内容，在外部工具（如 Postman）中进行复现。</li></ul><hr><p><strong>相关阅读</strong>：</p><ul><li><a href="./regex-pipeline">正则管道</a></li><li><a href="./context-compression">上下文压缩</a></li><li><a href="./../worldbook/">世界书管理</a></li></ul>',21)])])}const p=e(o,[["render",i]]);export{g as __pageData,p as default};
